const livingRoomLatitude = "40.712776"; // example latitude for living room
const livingRoomLongitude = "-74.005974"; // example longitude for living room
const epsilon = 0.0005; // small tolerance for coordinate comparison
function isInLivingRoom(lat, lon) {
  const latNum = parseFloat(lat);
  const lonNum = parseFloat(lon);
  if (isNaN(latNum) || isNaN(lonNum)) return false;
  return Math.abs(latNum - parseFloat(livingRoomLatitude)) < epsilon && Math.abs(lonNum - parseFloat(livingRoomLongitude)) < epsilon;
}
if (!isInLivingRoom(DoButton.doButtonNewCommandCommon.Latitude, DoButton.doButtonNewCommandCommon.Longitude)) {
  Sonos.playFavorite.skip();
  Yeelight.setScene.skip();
} else {
