const noteText = DoNote.doNoteNewCommandCommon.NoteText || '';
const pattern = /Today at (\d{1,2})(?::(\d{2}))?\s*(am|pm)?/i;
const match = noteText.match(pattern);
if (!match) {
  IosCalendar.createCalendarEvent.skip();
} else {
  // Extract hour and minute
  let hour = parseInt(match[1], 10);
  let minute = match[2] ? parseInt(match[2], 10) : 0;
  const ampm = match[3] ? match[3].toLowerCase() : null;
  if (ampm === 'pm' && hour < 12) {
    hour += 12;
  } else if (ampm === 'am' && hour === 12) {
    hour = 0;
  }
  // Build start date string in format 'YYYY-MM-DD HH:mm'
  const year = Meta.currentUserTime.year();
  const month = Meta.currentUserTime.month() + 1; // month() is 0-based
  const date = Meta.currentUserTime.date();
  // Pad month, date, hour, minute
  const pad = (n) => n < 10 ? '0' + n : n;
  const startDateStr = `${year}-${pad(month)}-${pad(date)} ${pad(hour)}:${pad(minute)}`;
  IosCalendar.createCalendarEvent.setTitle('Do Not Disturb');
  IosCalendar.createCalendarEvent.setStartDate(startDateStr);
  IosCalendar.createCalendarEvent.setDuration('60');
  IosCalendar.createCalendarEvent.setNotes(noteText);
}

