const homeLatitude = 40.7128;
const homeLongitude = -74.0060;
const gardenLatitude = 40.7138;
const gardenLongitude = -74.0050;
const locationThreshold = 0.0015; // approx ~150m

function isNear(lat1, lon1, lat2, lon2) {
  const toNum = s => parseFloat(s);
  lat1 = toNum(lat1);
  lon1 = toNum(lon1);
  lat2 = toNum(lat2);
  lon2 = toNum(lon2);
  if (isNaN(lat1) || isNaN(lon1) || isNaN(lat2) || isNaN(lon2)) return false;
  const latDiff = Math.abs(lat1 - lat2);
  const lonDiff = Math.abs(lon1 - lon2);
  return latDiff <= locationThreshold && lonDiff <= locationThreshold;
}

const lat = DoButton.doButtonNewCommandCommon.Latitude;
const lon = DoButton.doButtonNewCommandCommon.Longitude;

if (!(isNear(lat, lon, homeLatitude, homeLongitude) || isNear(lat, lon, gardenLatitude, gardenLongitude))) {
  Magichue.togglelight.skip();
}

const keyword = 'vacation';
const title = GoogleCalendar.eventFromSearchStarts.Title.toLowerCase();
const description = GoogleCalendar.eventFromSearchStarts.Description.toLowerCase();
const location = GoogleCalendar.eventFromSearchStarts.Where.toLowerCase();
const eventStart = GoogleCalendar.eventFromSearchStarts.Starts;
const currentTime = Meta.currentUserTime;
const eventStartMoment = currentTime.clone().set({
  year: eventStart.getFullYear(),
  month: eventStart.getMonth(),
  date: eventStart.getDate(),
  hour: eventStart.getHours(),
  minute: eventStart.getMinutes(),
  second: eventStart.getSeconds(),
  millisecond: eventStart.getMilliseconds()
});
const minutesBeforeEvent = eventStartMoment.diff(currentTime, 'minutes');

// Skip if keyword 'vacation' not found in title, description, or location
if (!title.includes(keyword) && !description.includes(keyword) && !location.includes(keyword)) {
  Blink.networkArm.skip();
}

// Skip if current time is not exactly 15 minutes before event start
if (minutesBeforeEvent !== 15) {
  Blink.networkArm.skip();
}

